// ServiceToken represents an authenticated service token
type ServiceToken struct {
	ServiceName string
	IssuedAt    time.Time
	Signature   string
}

// TokenManager handles creation and validation of service mesh tokens
type TokenManager struct {
	secret         []byte
	revokedTokens  map[string]time.Time
	mu             sync.RWMutex
	trustedServices map[string]bool
}

func NewTokenManager(secret string, trustedServices []string) *TokenManager {
	tm := &TokenManager{
		secret:          []byte(secret),
		revokedTokens:   make(map[string]time.Time),
		trustedServices: make(map[string]bool),
	}
	for _, svc := range trustedServices {
		tm.trustedServices[svc] = true
	}
	// Start cleanup goroutine for expired revoked tokens
	go tm.cleanupRevokedTokens()
	return tm
}

func (tm *TokenManager) GenerateToken(serviceName string) (string, error) {
	tm.mu.RLock()
	if !tm.trustedServices[serviceName] {
		tm.mu.RUnlock()
		return "", fmt.Errorf("service %q is not trusted", serviceName)
	}
	tm.mu.RUnlock()

	issuedAt := time.Now().UTC()
	payload := fmt.Sprintf("%s|%d", serviceName, issuedAt.UnixNano())
	signature := tm.computeHMAC(payload)
	token := fmt.Sprintf("%s|%d|%s", serviceName, issuedAt.UnixNano(), signature)
	return token, nil
}

func (tm *TokenManager) ValidateToken(tokenStr string) (*ServiceToken, error) {
	parts := strings.SplitN(tokenStr, "|", 3)
	if len(parts) != 3 {
		return nil, fmt.Errorf("invalid token format")
	}

	serviceName := parts[0]
	issuedAtNano := parts[1]
	providedSignature := parts[2]

	// Check if service is trusted
	tm.mu.RLock()
	if !tm.trustedServices[serviceName] {
		tm.mu.RUnlock()
		return nil, fmt.Errorf("service %q is not trusted", serviceName)
	}
	tm.mu.RUnlock()

	// Verify signature
	payload := fmt.Sprintf("%s|%s", serviceName, issuedAtNano)
	expectedSignature := tm.computeHMAC(payload)
	if !hmac.Equal([]byte(providedSignature), []byte(expectedSignature)) {
		return nil, fmt.Errorf("invalid token signature")
	}

	// Check if token is revoked
	tm.mu.RLock()
	if _, revoked := tm.revokedTokens[tokenStr]; revoked {
		tm.mu.RUnlock()
		return nil, fmt.Errorf("token has been revoked")
	}
	tm.mu.RUnlock()

	// Parse issued time and check expiration
	var issuedAtNanoInt int64
	if _, err := fmt.Sscanf(issuedAtNano, "%d", &issuedAtNanoInt); err != nil {
		return nil, fmt.Errorf("invalid token timestamp")
	}
	issuedAt := time.Unix(0, issuedAtNanoInt)
	if time.Since(issuedAt) > tokenExpiration {
		return nil, fmt.Errorf("token has expired")
	}

	return &ServiceToken{
		ServiceName: serviceName,
		IssuedAt:    issuedAt,
		Signature:   providedSignature,
	}, nil
}

func (tm *TokenManager) RevokeToken(tokenStr string) {
	tm.mu.Lock()
	defer tm.mu.Unlock()
	tm.revokedTokens[tokenStr] = time.Now()
}

func (tm *TokenManager) computeHMAC(message string) string {
	mac := hmac.New(sha256.New, tm.secret)
	mac.Write([]byte(message))
	return hex.EncodeToString(mac.Sum(nil))
}

func (tm *TokenManager) cleanupRevokedTokens() {
	ticker := time.NewTicker(10 * time.Minute)
	defer ticker.Stop()
	for range ticker.C {
		tm.mu.Lock()
		for token, revokedAt := range tm.revokedTokens {
			if time.Since(revokedAt) > tokenExpiration*2 {
				delete(tm.revokedTokens, token)
			}
		}
		tm.mu.Unlock()
	}
}

