// UnaryInterceptor handles authentication for unary RPCs
func (ai *AuthInterceptor) UnaryInterceptor() grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		// Skip auth for health check
		if info.FullMethod == "/mesh.MeshService/HealthCheck" {
			return handler(ctx, req)
		}

		newCtx, err := ai.authenticate(ctx)
		if err != nil {
			log.Printf("Authentication failed for %s: %v", info.FullMethod, err)
			return nil, err
		}

		log.Printf("Authenticated request to %s from service %s",
			info.FullMethod, ServiceNameFromContext(newCtx))

		return handler(newCtx, req)
	}
}

// StreamInterceptor handles authentication for streaming RPCs
func (ai *AuthInterceptor) StreamInterceptor() grpc.StreamServerInterceptor {
	return func(
		srv interface{},
		ss grpc.ServerStream,
		info *grpc.StreamServerInfo,
		handler grpc.StreamHandler,
	) error {
		newCtx, err := ai.authenticate(ss.Context())
		if err != nil {
			log.Printf("Stream authentication failed for %s: %v", info.FullMethod, err)
			return err
		}

		log.Printf("Authenticated stream to %s from service %s",
			info.FullMethod, ServiceNameFromContext(newCtx))

		wrapped := &wrappedServerStream{
			ServerStream: ss,
			ctx:          newCtx,
		}
		return handler(srv, wrapped)
	}
}

func (ai *AuthInterceptor) authenticate(ctx context.Context) (context.Context, error) {
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return nil, status.Errorf(codes.Unauthenticated, "missing metadata")
	}

	// Extract authorization token
	authValues := md.Get(tokenHeader)
	if len(authValues) == 0 {
		return nil, status.Errorf(codes.Unauthenticated, "missing authorization token")
	}

	tokenStr := authValues[0]
	// Strip "Bearer " prefix if present
	if strings.HasPrefix(tokenStr, "Bearer ") {
		tokenStr = strings.TrimPrefix(tokenStr, "Bearer ")
	}

	// Validate the token
	serviceToken, err := ai.tokenManager.ValidateToken(tokenStr)
	if err != nil {
		return nil, status.Errorf(codes.Unauthenticated, "invalid token: %v", err)
	}

	// Extract optional metadata
	var requestID string
	if ids := md.Get(requestIDHeader); len(ids) > 0 {
		requestID = ids[0]
	}

	// Add authentication info to context
	newCtx := context.WithValue(ctx, contextKeyServiceName, serviceToken.ServiceName)
	newCtx = context.WithValue(newCtx, contextKeyServiceToken, serviceToken)
	if requestID != "" {
		newCtx = context.WithValue(newCtx, contextKeyRequestID, requestID)
	}

	return newCtx, nil
}

