func (s *MeshServiceServer) GetData(ctx context.Context, req *GetDataRequest) (*GetDataResponse, error) {
	incrementRequestCount()
	callerService := ServiceNameFromContext(ctx)
	log.Printf("GetData called by service %q for key %q (request_id: %s)",
		callerService, req.Key, RequestIDFromContext(ctx))

	dataStoreMu.RLock()
	value, exists := dataStore[req.Key]
	dataStoreMu.RUnlock()

	if !exists {
		return nil, status.Errorf(codes.NotFound, "key %q not found", req.Key)
	}

	return &GetDataResponse{
		Key:   req.Key,
		Value: value,
	}, nil
}

func (s *MeshServiceServer) PutData(ctx context.Context, req *PutDataRequest) (*PutDataResponse, error) {
	incrementRequestCount()
	callerService := ServiceNameFromContext(ctx)
	log.Printf("PutData called by service %q for key %q (request_id: %s)",
		callerService, req.Key, RequestIDFromContext(ctx))

	if req.Key == "" {
		return nil, status.Errorf(codes.InvalidArgument, "key cannot be empty")
	}

	dataStoreMu.Lock()
	dataStore[req.Key] = req.Value
	dataStoreMu.Unlock()

	return &PutDataResponse{
		Success: true,
		Message: fmt.Sprintf("key %q stored successfully", req.Key),
	}, nil
}

func (s *MeshServiceServer) ServiceInfo(ctx context.Context, req *ServiceInfoRequest) (*ServiceInfoResponse, error) {
	incrementRequestCount()
	callerService := ServiceNameFromContext(ctx)

	requestCountMu.Lock()
	count := requestCount
	requestCountMu.Unlock()

	return &ServiceInfoResponse{
		ServiceName:   "mesh-data-service",
		Uptime:        time.Since(startTime).String(),
		RequestCount:  count,
		CallerService: callerService,
	}, nil
}

