// ServiceMeshCredentials implements grpc.PerRPCCredentials for service mesh auth
type ServiceMeshCredentials struct {
	tokenManager *TokenManager
	serviceName  string
}

func NewServiceMeshCredentials(tm *TokenManager, serviceName string) *ServiceMeshCredentials {
	return &ServiceMeshCredentials{
		tokenManager: tm,
		serviceName:  serviceName,
	}
}

func (c *ServiceMeshCredentials) GetRequestMetadata(ctx context.Context, uri ...string) (map[string]string, error) {
	token, err := c.tokenManager.GenerateToken(c.serviceName)
	if err != nil {
		return nil, fmt.Errorf("failed to generate token: %w", err)
	}
	return map[string]string{
		tokenHeader:   "Bearer " + token,
		serviceHeader: c.serviceName,
	}, nil
}

func (c *ServiceMeshCredentials) RequireTransportSecurity() bool {
	// In production, this should return true
	return false
}

