func main() {
	// Suppress unused import warnings
	_ = protogen.Options{}

	// Define trusted services in the mesh
	trustedServices := []string{
		"api-gateway",
		"user-service",
		"order-service",
		"payment-service",
		"notification-service",
		"inventory-service",
	}

	// Initialize token manager
	tokenManager := NewTokenManager(hmacSecret, trustedServices)

	// Create auth interceptor
	authInterceptor := NewAuthInterceptor(tokenManager)

	// Create gRPC server with interceptors
	server := grpc.NewServer(
		grpc.UnaryInterceptor(authInterceptor.UnaryInterceptor()),
		grpc.StreamInterceptor(authInterceptor.StreamInterceptor()),
	)

	// Register the mesh service
	meshService := NewMeshServiceServer(tokenManager)
	server.RegisterService(&meshServiceDesc, meshService)

	// Pre-populate some data
	dataStore["config:db_host"] = "postgres.internal:5432"
	dataStore["config:cache_host"] = "redis.internal:6379"
	dataStore["config:queue_host"] = "rabbitmq.internal:5672"

	// Start listening
	port := ":50051"
	listener, err := net.Listen("tcp", port)
	if err != nil {
		log.Fatalf("Failed to listen on %s: %v", port, err)
	}

	log.Printf("Mesh gRPC service starting on %s", port)
	log.Printf("Trusted services: %v", trustedServices)

	// Demo: Generate a sample token for testing
	sampleToken, err := tokenManager.GenerateToken("api-gateway")
	if err != nil {
		log.Printf("Failed to generate sample token: %v", err)
	} else {
		log.Printf("Sample token for api-gateway: %s", sampleToken)
	}

	// Start a goroutine to demonstrate client-side usage
	go func() {
		time.Sleep(2 * time.Second)
		demonstrateClientCall(tokenManager)
	}()

	if err := server.Serve(listener); err != nil {
		log.Fatalf("Failed to serve: %v", err)
	}
}

// demonstrateClientCall shows how another service in the mesh would make authenticated calls
func demonstrateClientCall(tm *TokenManager) {
	log.Println("--- Demonstrating client-side authenticated call ---")

	// Create credentials for the calling service
	creds := NewServiceMeshCredentials(tm, "api-gateway")

	// Connect to the mesh service
	conn, err := grpc.Dial(
		"localhost:50051",
		grpc.WithInsecure(),
		grpc.WithPerRPCCredentials(creds),
	)
	if err != nil {
		log.Printf("Client: failed to connect: %v", err)
		return
	}
	defer conn.Close()

	log.Println("Client: Connected to mesh service with authenticated credentials")
	log.Println("Client: Service mesh communication ready")

	// In a real scenario, you would use the generated client stub to make calls.
	// The PerRPCCredentials automatically injects the auth token into metadata
	// for every request.

	// Example of manually adding metadata (alternative to PerRPCCredentials):
	token, _ := tm.GenerateToken("order-service")
	md := metadata.New(map[string]string{
		tokenHeader:     "Bearer " + token,
		serviceHeader:   "order-service",
		requestIDHeader: "req-12345-abcde",
	})
	ctx := metadata.NewOutgoingContext(context.Background(), md)
	_ = ctx // Would be used with the client stub

	log.Println("Client: Metadata prepared for authenticated request")
}